@inject Services.WarehouseState WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<div class="warehouse-selector">
    <label class="form-label text-white mb-1" for="warehouse-dropdown">Current Warehouse</label>
    <select id="warehouse-dropdown"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in Services.WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    private void HandleStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChanged;
    }
}

@inject Services.InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        if (_handler is not null)
            AlertService.OnAlertCountChanged -= _handler;
    }
}

@page "/dashboard"
@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Site</h5>
        <p class="card-text fs-4">@WarehouseState.CurrentWarehouseName (@WarehouseState.CurrentWarehouseId)</p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body d-flex align-items-center gap-3">
        <h5 class="card-title mb-0">Low-Stock Alerts</h5>
        <AlertBadge />
        <span class="text-muted small">Refreshes every 10 seconds</span>
    </div>
    <div class="card-body border-top">
        @if (AlertService.CurrentAlertCount > 0)
        {
            <div class="alert alert-warning mb-0">
                ⚠️ <strong>@AlertService.CurrentAlertCount</strong> items are below minimum stock levels
                at @WarehouseState.CurrentWarehouseName.
            </div>
        }
        else
        {
            <div class="alert alert-success mb-0">
                ✅ All items at @WarehouseState.CurrentWarehouseName are above minimum stock levels.
            </div>
        }
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override async Task OnInitializedAsync()
    {
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;

        // Initial fetch + start polling
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        StartPolling();
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — refresh immediately and restart the timer
        StopPolling();
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken token)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(token))
            {
                await InvokeAsync(async () =>
                    await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId));
            }
        }
        catch (OperationCanceledException) { }
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
        _cts = null;
        _timer = null;
    }

    public void Dispose()
    {
        StopPolling();
        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;
        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

