@inject Services.WarehouseState WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<div class="warehouse-selector">
    <label class="form-label text-white mb-1" for="warehouse-dropdown">Current Warehouse</label>
    <select id="warehouse-dropdown"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in Services.WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    private void HandleStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChanged;
    }
}

